"""
Status runtime for AgentCube CLI.

Handles checking the status of deployed agents.

Copyright 2025 The Volcano Authors.
Licensed under the Apache License, Version 2.0.
"""

import logging
from pathlib import Path
from typing import Dict, Any

from ..services.metadata_service import MetadataService
from ..services.agentcube_provider import AgentCubeProvider
from ..services.k8s_provider import KubernetesProvider

logger = logging.getLogger(__name__)


class StatusRuntime:
    """Runtime for checking agent status."""

    def __init__(self, verbose: bool = False) -> None:
        self.verbose = verbose
        self.logger = logging.getLogger(__name__)
        self.metadata_service = MetadataService(verbose=verbose)

    def get_status(
        self,
        workspace_path: Path,
        provider: str = "agentcube",
    ) -> Dict[str, Any]:
        """Get the status of the deployed agent."""
        # Load metadata
        metadata = self.metadata_service.load_metadata(workspace_path)

        # Check if published
        if not metadata.k8s_deployment:
            return {
                "agent_name": metadata.agent_name,
                "status": "not_published",
                "provider": provider,
                "message": "Agent has not been published yet",
            }

        # Get status based on provider
        if provider == "agentcube":
            return self._get_agentcube_status(metadata)
        elif provider == "k8s":
            return self._get_k8s_status(metadata)
        else:
            raise ValueError(f"Unknown provider: {provider}")

    def _get_agentcube_status(self, metadata) -> Dict[str, Any]:
        """Get status from AgentCube."""
        k8s_deployment = metadata.k8s_deployment or {}
        namespace = k8s_deployment.get("namespace", "default")
        cr_name = k8s_deployment.get("cr_name")

        if not cr_name:
            return {
                "agent_name": metadata.agent_name,
                "status": "error",
                "provider": "agentcube",
                "message": "CR name not found in metadata",
            }

        provider = AgentCubeProvider(
            namespace=namespace,
            verbose=self.verbose,
        )

        try:
            cr = provider.get_agent_runtime(cr_name, namespace)

            if cr is None:
                return {
                    "agent_name": metadata.agent_name,
                    "status": "not_found",
                    "provider": "agentcube",
                    "cr_name": cr_name,
                    "namespace": namespace,
                    "message": f"AgentRuntime CR '{cr_name}' not found in namespace '{namespace}'",
                }

            # Determine status from CR
            status = cr.get("status", {})
            conditions = status.get("conditions", [])

            ready = False
            for condition in conditions:
                if condition.get("type") == "Ready":
                    ready = condition.get("status") == "True"
                    break

            return {
                "agent_name": metadata.agent_name,
                "status": "ready" if ready else "pending",
                "provider": "agentcube",
                "cr_name": cr_name,
                "namespace": namespace,
                "ready": ready,
                "conditions": conditions,
            }

        except Exception as e:
            self.logger.error(f"Failed to get AgentCube status: {e}")
            return {
                "agent_name": metadata.agent_name,
                "status": "error",
                "provider": "agentcube",
                "cr_name": cr_name,
                "namespace": namespace,
                "message": str(e),
            }

    def _get_k8s_status(self, metadata) -> Dict[str, Any]:
        """Get status from standard Kubernetes."""
        k8s_deployment = metadata.k8s_deployment or {}
        namespace = k8s_deployment.get("namespace", "default")
        deployment_name = k8s_deployment.get("deployment_name")

        if not deployment_name:
            return {
                "agent_name": metadata.agent_name,
                "status": "error",
                "provider": "k8s",
                "message": "Deployment name not found in metadata",
            }

        provider = KubernetesProvider(
            namespace=namespace,
            verbose=self.verbose,
        )

        try:
            status = provider.get_agent_status(metadata.agent_name)

            # Add additional info
            status["agent_name"] = metadata.agent_name
            status["provider"] = "k8s"
            status["service_url"] = k8s_deployment.get("service_url")

            return status

        except Exception as e:
            self.logger.error(f"Failed to get K8s status: {e}")
            return {
                "agent_name": metadata.agent_name,
                "status": "error",
                "provider": "k8s",
                "deployment_name": deployment_name,
                "namespace": namespace,
                "message": str(e),
            }

